import React, {createRef} from "react";
import CanvasDraw from "react-canvas-draw";

class Canvas extends React.Component {



    constructor(props) {
        super(props);
        this.state = {


        };

        this.myP = createRef();
        window.addEventListener("load", ()=>this.prompt());
    }

    prompt(){
        const ctx = this.myP.current.getContext("2d");
        ctx?.strokeRect(200, 200, 40, 50);
    }


    componentDidMount() {

    }

    render() {


        var content = []
        var header = ""

        content.push(<CanvasDraw ref={this.myP} canvasWidth={window.innerWidth} canvasHeight={window.innerHeight} style={{ border: "2px solid black" }}/>)


        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>
        );
    }

}

export default Canvas
